--
-- Table structure for table `matches`
--

DROP TABLE IF EXISTS `matches`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `matches` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `tournament_id` bigint unsigned NOT NULL,
  `home_team_id` bigint unsigned DEFAULT NULL,
  `away_team_id` bigint unsigned DEFAULT NULL,
  `round_no` smallint unsigned DEFAULT NULL,
  `bracket_stage` enum('GROUP','QUARTER','SEMI','FINAL') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `scheduled_at` datetime DEFAULT NULL,
  `venue` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('SCHEDULED','LIVE','COMPLETED','CANCELLED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'SCHEDULED',
  `home_score` int NOT NULL DEFAULT '0',
  `away_score` int NOT NULL DEFAULT '0',
  `home_wickets` tinyint DEFAULT NULL,
  `away_wickets` tinyint DEFAULT NULL,
  `home_overs` decimal(4,1) DEFAULT NULL,
  `away_overs` decimal(4,1) DEFAULT NULL,
  `winner_team_id` bigint unsigned DEFAULT NULL,
  `minute_clock` int NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `summary_json` longtext COLLATE utf8mb4_unicode_ci,
  `mom_player_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_matches_home` (`home_team_id`),
  KEY `fk_matches_away` (`away_team_id`),
  KEY `fk_matches_winner` (`winner_team_id`),
  KEY `idx_matches_tournament` (`tournament_id`),
  KEY `idx_matches_status` (`status`),
  KEY `idx_matches_schedule` (`scheduled_at`),
  KEY `fk_matches_mom` (`mom_player_id`),
  CONSTRAINT `fk_matches_away` FOREIGN KEY (`away_team_id`) REFERENCES `teams` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_matches_home` FOREIGN KEY (`home_team_id`) REFERENCES `teams` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_matches_mom` FOREIGN KEY (`mom_player_id`) REFERENCES `players` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_matches_tournament` FOREIGN KEY (`tournament_id`) REFERENCES `tournaments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_matches_winner` FOREIGN KEY (`winner_team_id`) REFERENCES `teams` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=55 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

